import { GOATCOUNTER_CODE } from "../config";

const SCRIPT_SRC = "https://gc.zgo.at/count.js";

export function initGoatCounter() {
    if (!GOATCOUNTER_CODE || process.env.NODE_ENV !== "production") {
        return;
    }

    if (document.querySelector(`script[src="${SCRIPT_SRC}"]`)) {
        return;
    }

    window.goatcounter = {
        ...(window.goatcounter || {}),
        no_onload: true,
    };

    const script = document.createElement("script");
    script.async = true;
    script.src = SCRIPT_SRC;
    script.dataset.goatcounter = `https://${GOATCOUNTER_CODE}.goatcounter.com/count`;
    document.body.appendChild(script);
}

export function trackPageview(path) {
    if (!GOATCOUNTER_CODE || process.env.NODE_ENV !== "production") {
        return;
    }

    const send = () => {
        if (typeof window.goatcounter?.count === "function") {
            window.goatcounter.count({
                path: path || `${window.location.pathname}${window.location.search}${window.location.hash}`,
            });
        }
    };

    if (typeof window.goatcounter?.count === "function") {
        send();
        return;
    }

    const script = document.querySelector(`script[src="${SCRIPT_SRC}"]`);
    if (script) {
        script.addEventListener("load", send, { once: true });
    }
}
